1	/**
2	 * LayerInfinite MCP Server — episode-tracker.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Gap Fix #2: Redirect Loop Prevention
5	 *
6	 * Tracks tried/failed actions per episode to prevent redirect loops
7	 * in assist/auto modes. When auto mode redirects from A to B and B
8	 * fails, the fallback logic must not redirect back to A.
9	 *
10	 * Entries expire after 30 minutes to prevent memory leaks.
11	 * ══════════════════════════════════════════════════════════════
12	 */
13	
14	const EXPIRY_MS = 30 * 60 * 1000; // 30 minutes
15	
16	interface EpisodeEntry {
17	  triedActions: Set<string>;
18	  createdAt: number;
19	}
20	
21	/**
22	 * Lightweight in-memory tracker for actions tried within an episode.
23	 * Not persisted — if the MCP server restarts, episodes start fresh.
24	 * This is acceptable because episodes are short-lived (minutes, not hours).
25	 */
26	export class EpisodeTracker {
27	  private readonly episodes = new Map<string, EpisodeEntry>();
28	
29	  /** Record that an action was tried in this episode. */
30	  markTried(episodeId: string, actionName: string): void {
31	    this.cleanExpired();
32	    let entry = this.episodes.get(episodeId);
33	    if (!entry) {
34	      entry = { triedActions: new Set(), createdAt: Date.now() };
35	      this.episodes.set(episodeId, entry);
36	    }
37	    entry.triedActions.add(actionName);
38	  }
39	
40	  /** Get all tried actions for an episode. */
41	  getTriedActions(episodeId: string): ReadonlySet<string> {
42	    this.cleanExpired();
43	    return this.episodes.get(episodeId)?.triedActions ?? new Set();
44	  }
45	
46	  /** Check if an action has already been tried in this episode. */
47	  hasTried(episodeId: string, actionName: string): boolean {
48	    return this.getTriedActions(episodeId).has(actionName);
49	  }
50	
51	  /** Remove expired entries to prevent memory leaks. */
52	  private cleanExpired(): void {
53	    const now = Date.now();
54	    for (const [id, entry] of this.episodes) {
55	      if (now - entry.createdAt > EXPIRY_MS) {
56	        this.episodes.delete(id);
57	      }
58	    }
59	  }
60	}
